import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Trash, ArrowLeft, 
  Eye, X, ShoppingBasket, Edit2, Calendar, Tag, Package
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; 

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ 
    id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [mostrarGaleria, setMostrarGaleria] = useState(false);
  const [editando, setEditando] = useState(null); // Estado para el modal de edición

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  // --- LÓGICA DE AGRUPACIÓN POR FECHAS ---
  const agruparPorFecha = () => {
    const grupos = {};
    publicados.forEach(p => {
      const fechaKey = p.fechaFinOferta ? new Date(p.fechaFinOferta).toLocaleDateString() : 'Sin Fecha';
      if (!grupos[fechaKey]) grupos[fechaKey] = [];
      grupos[fechaKey].push(p);
    });
    return grupos;
  };

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => {
      const refLimpia = norm(f.nombreReferencia.split('.')[0]); 
      return refLimpia.includes(textoLimpio) || textoLimpio.includes(refLimpia);
    });
  }, [galeria]);

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(l => l.trim() !== '');
    const nuevas = lineas.map(line => {
      const c = line.split('\t');
      const nombre = c[0]?.trim() || '';
      const m = buscarMatch(nombre);
      return { 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: c[1] || '', 
        precioViejo: c[2] || '', 
        stock: c[3] || 0, 
        categoria: c[4] || 'Almacén', 
        fotoSugerida: m ? m.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");
    setCargando(true);
    try {
      const productos = validas.map(f => ({
        ...f,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));
      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      setFilas([filaInicial()]);
      cargarDatos();
      alert("¡Tanda publicada con éxito!");
    } catch (e) { alert("Error al publicar."); } 
    finally { setCargando(false); }
  };

  const actualizarProducto = async () => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${editando._id}`, editando);
      setEditando(null);
      cargarDatos();
      alert("Producto actualizado");
    } catch (e) { alert("Error al actualizar"); }
  };

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') return <div style={placeholderStyle}><ImageIcon color="#cbd5e1" size={20}/></div>;
    const fotoInfo = galeria.find(g => g.publicId === pid);
    const urlFinal = fotoInfo?.url 
      ? fotoInfo.url.replace('/upload/', `/upload/${size},c_fill,f_auto,q_auto/`)
      : `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill,f_auto,q_auto/${pid}`;

    return (
      <div style={thumbContainerStyle}>
        <img src={urlFinal} style={imgStyle} alt="P" onError={(e) => { e.target.style.display='none'; e.target.parentNode.style.background='#cbd5e1'; }}/>
      </div>
    );
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1300px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh' }}>
      
      {/* HEADER Y CONTROLES */}
      <div style={topHeader}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => setMostrarGaleria(!mostrarGaleria)} style={btnVerGaleria}>
                <Eye size={18}/> {mostrarGaleria ? "Cerrar Galería" : "Ver Biblioteca"}
            </button>
            <SubirImagenes onFinished={cargarDatos} />
        </div>
      </div>

      {/* SECCIÓN DE CARGA (TABLA EXPANDIDA) */}
      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold', display:'flex', alignItems:'center', gap:8 }}><Sparkles size={20}/> Nueva Tanda de Ofertas</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Nueva Fila</button>
        </div>
        <div style={{overflowX: 'auto'}}>
          <table style={tableStyle}>
            <thead>
              <tr style={tableHead}>
                <th style={thStyle}>Vista</th>
                <th style={thStyle}>Producto</th>
                <th style={thStyle}>$ Normal</th>
                <th style={thStyle}>$ Oferta</th>
                <th style={thStyle}>Stock</th>
                <th style={thStyle}>Categoría</th>
                <th style={{width: 40}}></th>
              </tr>
            </thead>
            <tbody>
              {filas.map(f => (
                <tr key={f.id} style={trStyle}>
                  <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                  <td style={tdStyle}><input style={inputTable} value={f.producto} placeholder="Nombre..." onChange={e => handleInputChange(f.id, 'producto', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} type="number" placeholder="0" value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} type="number" placeholder="0" value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} type="number" placeholder="0" value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                  <td style={tdStyle}>
                    <select value={f.categoria} onChange={e => handleInputChange(f.id, 'categoria', e.target.value)} style={selectStyle}>
                      <option>Almacén</option><option>Carnicería</option><option>Verdulería</option><option>Lácteos</option><option>Limpieza</option><option>Panadería</option>
                    </select>
                  </td>
                  <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={btnDelRow}><X size={18}/></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 15, alignItems: 'center' }}>
            <span style={{fontSize: '0.8rem', color:'#64748b'}}>Validez:</span>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <span style={{color:'#cbd5e1'}}>→</span>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>{cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} PUBLICAR TANDA</button>
        </div>
      </section>

      {/* PRODUCTOS EN LA NUBE AGRUPADOS */}
      <h2 style={{ color: '#1e293b', marginBottom: '25px', display:'flex', alignItems:'center', gap:10 }}>
        <Package color="#e67e22"/> Tandas Activas en la Nube
      </h2>

      {Object.entries(agruparPorFecha()).map(([fecha, productos]) => (
        <div key={fecha} style={tandaSection}>
          <div style={tandaHeader}>
            <Calendar size={16}/> Vence el: <strong>{fecha}</strong> 
            <span style={tandaBadge}>{productos.length} Productos</span>
          </div>
          <div style={gridStyle}>
            {productos.map(p => (
              <div key={p._id} style={itemCard}>
                <div style={itemBadges}>
                  <span style={catBadge}>{p.categoria}</span>
                  <span style={stockBadge(p.stock)}>Stock: {p.stock}</span>
                </div>
                <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_150")}</div>
                <h4 style={itemTitle}>{p.producto}</h4>
                <div style={priceContainer}>
                  <span style={oldPrice}>${p.precioViejo}</span>
                  <span style={newPrice}>${p.precioNuevo}</span>
                </div>
                <div style={cardActions}>
                  <button onClick={() => setEditando(p)} style={btnEdit}><Edit2 size={14}/> Editar</button>
                  <button onClick={async () => { if(window.confirm("¿Borrar?")){ await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarDatos(); }}} style={btnDelete}><Trash size={14}/></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}

      {/* MODAL DE EDICIÓN RÁPIDA */}
      {editando && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <h3>Editar Producto</h3>
            <label style={labelStyle}>Nombre del Producto</label>
            <input style={inputModal} value={editando.producto} onChange={e => setEditando({...editando, producto: e.target.value})}/>
            
            <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, marginTop:15}}>
              <div>
                <label style={labelStyle}>Precio Normal</label>
                <input style={inputModal} type="number" value={editando.precioViejo} onChange={e => setEditando({...editando, precioViejo: e.target.value})}/>
              </div>
              <div>
                <label style={labelStyle}>Precio Oferta</label>
                <input style={inputModal} type="number" value={editando.precioNuevo} onChange={e => setEditando({...editando, precioNuevo: e.target.value})}/>
              </div>
            </div>

            <div style={{marginTop:15}}>
              <label style={labelStyle}>Stock Disponible</label>
              <input style={inputModal} type="number" value={editando.stock} onChange={e => setEditando({...editando, stock: e.target.value})}/>
            </div>

            <div style={modalActions}>
              <button onClick={() => setEditando(null)} style={btnCancel}>Cancelar</button>
              <button onClick={actualizarProducto} style={btnSave}>Guardar Cambios</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

